const repos = [
  { ownerRepo: 'mrhz1973/control-plane', stateKey: 'github:mrhz1973/control-plane:last_commit_sha', sourceRepo: 'mrhz1973/control-plane' },
  { ownerRepo: 'mrhz1973/dev-method', stateKey: 'github:mrhz1973/dev-method:last_commit_sha', sourceRepo: 'mrhz1973/dev-method' },
  { ownerRepo: 'mrhz1973/cursor-coordinate-converter', stateKey: 'github:mrhz1973/cursor-coordinate-converter:last_commit_sha', sourceRepo: 'mrhz1973/cursor-coordinate-converter' }
];
return repos.map((r) => ({ json: r }));

const target = $('Emit watched repos (3)').item.json;
const resp = $input.item.json;
const commit = Array.isArray(resp) ? resp[0] : resp;
const sha = commit?.sha || '';
const rawMessage = commit?.commit?.message || 'no commit message';
const message = rawMessage.split('\n')[0];
const url = commit?.html_url || 'no URL';
return { json: { stateKey: target.stateKey, currentSha: sha, shortSha: sha ? sha.substring(0, 7) : '', message, url, sourceRepo: target.sourceRepo, ownerRepo: target.ownerRepo } };

const prepareItems = $('Prepare latest commit event').all();
const stateRows = $('Data Table - Load all state rows').all().map((entry) => entry.json);
return prepareItems.map((item) => { const latest = item.json; const row = stateRows.find((r) => r.key === latest.stateKey); const storedValue = row?.value || ''; const isNew = Boolean(latest.currentSha && latest.currentSha !== storedValue); return { json: { ...latest, previousSha: storedValue || '', isNew, hadStateRow: Boolean(row?.key) } }; });

const latest = $('Decide Data Table dedupe').item.json;
const previous = latest.previousSha ? latest.previousSha.substring(0, 7) : 'none';
const title = latest.message || 'no commit message';
return { json: { text: `CONTROL PLANE scheduled poll commit notification
Repo: ${latest.sourceRepo}
New commit: ${latest.shortSha}
Previous: ${previous}
Message: ${title}
URL: ${latest.url}` } };

const item = $input.first().json;
const stdout = String(item.stdout || item.data || item.output || '');
const stderr = String(item.stderr || '');
const exitCode = item.exitCode ?? item.code ?? item.exit_code ?? 0;
const fullPromptPath = '/home/node/.n8n-files/latest-gis-handoff.md';
const attachedFileName = 'latest-gis-handoff.md';
function extractLine(label, fallback = '[not found]') { const escaped = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); const re = new RegExp(`^${escaped}:\\s*(.*)$`, 'mi'); const m = stdout.match(re); return m && m[1] ? m[1].trim() : fallback; }
function extractGeneratedPrompt() { const marker = '## Generated prompt'; const idx = stdout.indexOf(marker); if (idx === -1) return ''; let tail = stdout.slice(idx + marker.length); tail = tail.replace(/^\s+/, ''); const safetyIdx = tail.search(/\n---\s*\n\s*## Safety summary/i); if (safetyIdx !== -1) tail = tail.slice(0, safetyIdx); return tail.trim(); }
function oneLine(value, fallback = '[not found]') { const s = String(value ?? '').replace(/\r?\n/g, ' ').replace(/\s+/g, ' ').trim(); return s || fallback; }
function limit(value, max = 180) { const s = oneLine(value); return s.length > max ? s.slice(0, max - 3).trimEnd() + '...' : s; }
const promptReady = extractLine('Prompt ready', 'no');
const operationType = extractLine('Operation type', '[not found]');
const riskLevel = extractLine('Risk level', '[not found]');
const operationalRepo = extractLine('Operational repo', 'cursor-coordinate-converter');
const generatedPrompt = extractGeneratedPrompt();
const promptLines = generatedPrompt.split(/\r?\n/).map(s => s.trim()).filter(Boolean);
const taskLine = promptLines.find(l => /^TASK:/i.test(l)) || promptLines[0] || '[prompt title not found]';
const generatedPromptLength = generatedPrompt.length || 0;
const nextAction = promptReady.toLowerCase().startsWith('yes') ? `Open Telegram attachment ${attachedFileName} and use it in Cursor GIS.` : `Do not paste to Cursor yet. Inspect n8n execution and attached ${attachedFileName}.`;
const telegramText = ['CONTROL PLANE handoff', `Prompt ready: ${limit(promptReady, 80)}`, `Target: ${limit(operationalRepo, 120)}`, `Task: ${limit(taskLine, 220)}`, `Operation type: ${limit(operationType, 80)}`, `Risk level: ${limit(riskLevel, 80)}`, `Generated prompt available: ${generatedPrompt ? 'yes' : 'no'}`, `Generated prompt length: ${generatedPromptLength}`, `Exit code: ${exitCode}`, '', `Full prompt file: ${attachedFileName}`, `Path in n8n: ${fullPromptPath}`, `Next action: ${nextAction}`, '', 'Prompt preview omitted intentionally. Full prompt is attached as a .md file.'].join('\n');
return [{ json: { promptReady, operationType, riskLevel, target: operationalRepo, exitCode, stderr, fullPromptPath, attachedFileName, generatedPromptFound: Boolean(generatedPrompt), generatedPromptLength, taskLine, telegramText } }];

const repo = String($json.ownerRepo || $json.sourceRepo || '').trim();
const isControlPlane = repo === 'mrhz1973/control-plane';
return { json: { event: isControlPlane ? 'plan_branch_entered' : 'plan_branch_skipped', repo, stateKey: $json.stateKey, currentSha: $json.currentSha, shortSha: $json.shortSha, latestCommitUrl: $json.url, latestCommitMessage: $json.message, previousSha: $json.previousSha, gate: 'C-dropin-candidate', gateD: 'not_authorized' } };

const commit = $input.first().json;
const gate = $('Code - Plan watcher repo gate stub').first().json;
const files = Array.isArray(commit.files) ? commit.files : [];
const planFiles = files.filter((f) => /^docs\/plans\/[^/]+\.plan\.md$/.test(String(f.filename || '')));
if (!planFiles.length) { return [{ json: { event: 'no_plan_detected', repo: gate.repo, commitSha: gate.currentSha, shortSha: gate.shortSha, changedFileCount: files.length, changedFiles: files.map(f => f.filename).slice(0, 30), gate: 'C-dropin-candidate', gateD: 'not_authorized' } }]; }
return planFiles.map((f) => ({ json: { event: 'plan_detected', repo: gate.repo, commitSha: gate.currentSha, shortSha: gate.shortSha, planPath: f.filename, fileStatus: f.status || '', additions: f.additions ?? null, deletions: f.deletions ?? null, changes: f.changes ?? null, gate: 'C-dropin-candidate', nextGate: 'Gate D message delivery not authorized' } }));
